// anti-typicality-config.mjs — Sprint 16 Task 31.5
//
// Loads + validates anti-typicality configuration for Verbalized Sampling
// (Stage 1.5) and the originality_vs_history critic dimension. Reads
// `skills/visionary/anti-typicality.json` (or a custom path), then applies
// environment-variable overrides matching the existing VISIONARY_* convention.
//
// Why a dedicated file instead of extending calibration.json?
//   `calibration.json` is RUNTIME-GENERATED by the nightly regression refit
//   (apply-calibration.mjs writes per_dimension fits, status, prompt-hashes,
//   etc). Mixing static config with regression output would mean every
//   refit-cycle has to round-trip our anti-typicality block — a footgun.
//   This file is purely human-edited config; it never gets regenerated.
//
// Resolution order for each field:
//   1. Env-var override (parsed safely; bad input → fallback to step 2)
//   2. Value from JSON file (validated against the embedded schema; bad
//      values → fallback to step 3)
//   3. HARDCODED_DEFAULTS (Zhang 2025 + 2026-baseline)
//
// Env vars (matches sprint-16 doc):
//   VISIONARY_VS_ALPHA           (float)   → vs_alpha
//   VISIONARY_VS_DISABLED=1                → enabled: false
//   VISIONARY_DISABLE_VS=1                 → enabled: false (alias)
//   VISIONARY_ORIGINALITY_WEIGHT (float)   → originality_weight
//   VISIONARY_HISTORY_WINDOW     (integer) → originality_history_window
//
// Public API:
//   loadConfig(customPath?) → fully-resolved config object (always valid).
//   HARDCODED_DEFAULTS      → frozen defaults, exported for tests + introspection.

import { existsSync, readFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);

// repo-root/skills/visionary/anti-typicality.json
// __filename = repo-root/hooks/scripts/lib/anti-typicality-config.mjs
//   → ../ = lib (no-op),  ../../ = scripts, ../../../ = hooks, ../../../../ = repo-root
const DEFAULT_CONFIG_PATH = resolve(
  dirname(__filename),
  '..',
  '..',
  '..',
  'skills',
  'visionary',
  'anti-typicality.json',
);

export const HARDCODED_DEFAULTS = Object.freeze({
  enabled: true,
  vs_alpha: 0.65,
  vs_concept_count: 5,
  vs_convergence_threshold: 0.85,
  vs_max_retries_on_schema_fail: 1,
  originality_weight: 0.8,
  originality_history_window: 10,
  originality_history_max_age_days: 90,
  boost_factor_cap: 1.6,
  boost_factor_floor: 0.6,
  min_concept_quality_threshold: 0.3,
});

// ── Field-level constraints (mirror anti-typicality.schema.json) ────────────
// Kept inline so this module has no dep on the schema-validator and stays
// safe to import from any hook. A mismatch with the schema is caught by the
// __tests__/anti-typicality-config.test.mjs suite.
const FIELD_CONSTRAINTS = Object.freeze({
  enabled:                          { type: 'boolean' },
  vs_alpha:                         { type: 'number',  min: 0,   max: 2 },
  vs_concept_count:                 { type: 'integer', min: 3,   max: 10 },
  vs_convergence_threshold:         { type: 'number',  min: 0.5, max: 1 },
  vs_max_retries_on_schema_fail:    { type: 'integer', min: 0,   max: 5 },
  originality_weight:               { type: 'number',  min: 0,   max: 2 },
  originality_history_window:       { type: 'integer', min: 1,   max: 100 },
  originality_history_max_age_days: { type: 'integer', min: 1,   max: 365 },
  boost_factor_cap:                 { type: 'number',  min: 1,   max: 5 },
  boost_factor_floor:               { type: 'number',  min: 0,   max: 1 },
  min_concept_quality_threshold:    { type: 'number',  min: 0,   max: 1 },
});

// ── Env-parser helpers ──────────────────────────────────────────────────────
// Each helper takes (envName, fallback). On any parse failure the fallback is
// returned silently — we never crash a hook because of a typo'd env var.
function parseEnvFloat(envName, fallback) {
  const raw = process.env[envName];
  if (raw == null || raw === '') return fallback;
  const n = Number.parseFloat(raw);
  return Number.isFinite(n) ? n : fallback;
}

function parseEnvInt(envName, fallback) {
  const raw = process.env[envName];
  if (raw == null || raw === '') return fallback;
  // Reject "12.7" — that's a float, not an int. parseInt would silently
  // truncate which masks user error.
  const trimmed = String(raw).trim();
  if (!/^-?\d+$/.test(trimmed)) return fallback;
  const n = Number.parseInt(trimmed, 10);
  return Number.isFinite(n) ? n : fallback;
}

function parseEnvBool(envName, fallback) {
  const raw = process.env[envName];
  if (raw == null || raw === '') return fallback;
  const v = String(raw).trim().toLowerCase();
  if (v === '1' || v === 'true' || v === 'yes' || v === 'on') return true;
  if (v === '0' || v === 'false' || v === 'no' || v === 'off') return false;
  return fallback;
}

// ── Field-level validation ──────────────────────────────────────────────────
function isValidField(name, value) {
  const c = FIELD_CONSTRAINTS[name];
  if (!c) return false;
  if (c.type === 'boolean') return typeof value === 'boolean';
  if (c.type === 'number') {
    return typeof value === 'number' && Number.isFinite(value) && value >= c.min && value <= c.max;
  }
  if (c.type === 'integer') {
    return typeof value === 'number' && Number.isInteger(value) && value >= c.min && value <= c.max;
  }
  return false;
}

// ── File loader ─────────────────────────────────────────────────────────────
function readConfigFile(path) {
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, 'utf8');
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object') return null;
    const at = parsed.anti_typicality;
    if (!at || typeof at !== 'object' || Array.isArray(at)) return null;
    return at;
  } catch {
    return null;
  }
}

// ── Validation entry-point (exported for tests) ─────────────────────────────
// Validates an `anti_typicality` block against FIELD_CONSTRAINTS. Returns
// { ok, errors }. Errors contain field name + reason; never throws.
export function validateConfigBlock(block) {
  const errors = [];
  if (!block || typeof block !== 'object' || Array.isArray(block)) {
    return { ok: false, errors: [{ field: '<root>', message: 'block is not an object' }] };
  }
  for (const [name, constraint] of Object.entries(FIELD_CONSTRAINTS)) {
    if (!(name in block)) {
      errors.push({ field: name, message: 'missing required field' });
      continue;
    }
    if (!isValidField(name, block[name])) {
      errors.push({
        field: name,
        message: `value ${JSON.stringify(block[name])} fails constraint type=${constraint.type} min=${constraint.min ?? '-'} max=${constraint.max ?? '-'}`,
      });
    }
  }
  return errors.length === 0 ? { ok: true, errors: [] } : { ok: false, errors };
}

// ── Main loader ─────────────────────────────────────────────────────────────
// Three-stage merge: defaults <- file <- env. Each stage is field-by-field
// so a single bad value in the file doesn't poison the rest of the config.
export function loadConfig(customPath) {
  const path = customPath || DEFAULT_CONFIG_PATH;

  // Stage 1: start from hardcoded defaults (always valid).
  const merged = { ...HARDCODED_DEFAULTS };

  // Stage 2: overlay file values that pass field-level validation.
  const fileBlock = readConfigFile(path);
  if (fileBlock) {
    for (const name of Object.keys(FIELD_CONSTRAINTS)) {
      if (name in fileBlock && isValidField(name, fileBlock[name])) {
        merged[name] = fileBlock[name];
      }
      // Silent fall-through: bad file value → keep default. The caller
      // can re-validate via validateConfigBlock(fileBlock) for diagnostics.
    }
  }

  // Stage 3: env-var overrides. These trump the file because operators use
  // them for one-off A/B and CI overrides.
  merged.vs_alpha = parseEnvFloat('VISIONARY_VS_ALPHA', merged.vs_alpha);
  merged.originality_weight = parseEnvFloat('VISIONARY_ORIGINALITY_WEIGHT', merged.originality_weight);
  merged.originality_history_window = parseEnvInt('VISIONARY_HISTORY_WINDOW', merged.originality_history_window);

  // Two boolean disable-aliases. Either one set true forces enabled=false.
  // Both default to whatever `merged.enabled` already is, so an unset env
  // leaves the file/default decision intact.
  const vsDisabled = parseEnvBool('VISIONARY_VS_DISABLED', false);
  const vsDisabledAlias = parseEnvBool('VISIONARY_DISABLE_VS', false);
  if (vsDisabled || vsDisabledAlias) merged.enabled = false;

  // Re-clamp env-derived values into their constraints. An operator who sets
  // VISIONARY_VS_ALPHA=999 should get clamped to the schema max, not crash
  // the downstream sampler.
  for (const [name, value] of Object.entries(merged)) {
    if (!isValidField(name, value)) {
      merged[name] = HARDCODED_DEFAULTS[name];
    }
  }

  return merged;
}

// Exported for tests + tooling.
export { DEFAULT_CONFIG_PATH };
